export const majorCapabilityEvalCases = majorCapabilities.map((capability) => ({
  capabilityId: capability.id,
  capability: capability.label,
  description: capability.primaryCase.description ?? `${capability.label} primary dogfood case.`,
  safetyClass: capability.safetyClass,
  ...capability.primaryCase,
}));

export function buildMajorCapabilityExpandedCases() {
  return majorCapabilities.flatMap((capability) => {
    const base = buildCaseFromPrimary(capability);
    const paraphraseCases = capability.paraphrases.map((message, index) => ({
      ...base,
      id: `${capability.primaryCase.id}-paraphrase-${index + 1}`,
      description: `${capability.label} paraphrase: ${message}`,
      message,
    })).map((caseDef) => applyExpandedCaseOverrides(capability, caseDef));
    const stateCases = capability.stateCases.map((scenario) => ({
      ...base,
      id: `${capability.primaryCase.id}-state-${scenario}`,
      description: `${capability.label} in fake-data state ${scenario}.`,
      scenario,
    })).map((caseDef) => applyExpandedCaseOverrides(capability, caseDef));

    return [base, ...paraphraseCases, ...stateCases];
  });
}

function applyExpandedCaseOverrides(capability, caseDef) {
  const next = { ...caseDef };

  if (capability.id === "purchase_simulation" && next.id.includes("-paraphrase-")) {
    next.expectedTools = ["simulate_purchase"];
  }

  if (
    capability.id === "savings_goal_setup" &&
    ["I want to save for Japan", "Save for a big purchase"].includes(next.message)
  ) {
    delete next.expectedTools;
    delete next.expectedCards;
    next.expectedPendingActionType = "create_savings_goal";
    next.expectedResponseMode = "clarify";
    next.expectNoCards = true;
    next.routingOnly = false;
  }

  if (next.id === "major-cutback-opportunity-state-cash-guardrail") {
    delete next.expectedCards;
    next.expectedResponseMode = "chat_only";
    next.expectNoCards = true;
  }

  return next;
}

